import{_ as e,o as r,c as n,ag as a}from"./chunks/framework.eQLvDOR_.js";const u=JSON.parse('{"title":"agent-harness-pattern","description":"","frontmatter":{"title":"agent-harness-pattern","concept":"Agent Harness 模式","concept_id":"agent-harness-pattern","aliases":["harness","长周期agent","agentic-systems"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Effective harnesses for long-running agents.md","02_Library/Agent_Architecture/[Agent_Architecture] Harness-design-for-long-running-application-development.md","02_Library/Agent_Architecture/[Agent_Architecture] Building Effective AI Agents.md"],"related_concepts":["[[workflows-vs-agents]]","[[agent-computer-interface]]"],"created_at":"2026-04-04","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/agent-harness-pattern.md","filePath":"wiki/concepts/agent-harness-pattern.md","lastUpdated":null}'),i={name:"wiki/concepts/agent-harness-pattern.md"};function o(s,t,c,l,h,g){return r(),n("div",null,[...t[0]||(t[0]=[a('<h1 id="agent-harness-模式" tabindex="-1">Agent Harness 模式 <a class="header-anchor" href="#agent-harness-模式" aria-label="Permalink to &quot;Agent Harness 模式&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>长期运行 Agent 的容错、恢复框架及生命周期管理。本质上是将研发流程从“让 AI 协助人”重构为“人构建系统让 AI 输出可信工件”的过程。</p><h2 id="核心设计准则-anthropic-2026" tabindex="-1">核心设计准则 (Anthropic 2026) <a class="header-anchor" href="#核心设计准则-anthropic-2026" aria-label="Permalink to &quot;核心设计准则 (Anthropic 2026)&quot;">​</a></h2><ol><li><strong>Simplicity (简洁性)</strong>：保持 Agent 设计的简单，先由简单 Prompt 开始，必要时才引入多步 Agentic 系统。</li><li><strong>Transparency (透明性)</strong>：通过显式展示 Agent 的规划步骤来提高可解释性。</li><li><strong>ACI 驱动</strong>：通过深入的工具文档和测试，精心打磨 Agent-Computer Interface。</li></ol><h2 id="关键要点" tabindex="-1">关键要点 <a class="header-anchor" href="#关键要点" aria-label="Permalink to &quot;关键要点&quot;">​</a></h2><ul><li><strong>Ground Truth 校验</strong>：Agent 在每一步必须获取环境的真实反馈（如代码执行结果），以评估进度。</li><li><strong>检查点 (Checkpointing)</strong>：在遇到阻塞或到达关键节点时，允许 Agent 暂停并请求人类介入。</li><li><strong>停止条件</strong>：包含最大迭代次数等退出机制，防止死循环和成本失控。</li><li><strong>统一的代码全库视图</strong>：打破碎片化的 Repository，由于 AI 极难进行跨库的隐式推断，应强行转为 Monorepo 使得一切关系对 AI 显性化。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Why Your “AI-First” Strategy Is Probably Wrong.html">[Agent_Architecture] Why Your “AI-First” Strategy Is Probably Wrong.md</a>）</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>当开发需要持续数小时甚至数天的 Agent 任务时，不要写死大循环，而是利用 State Machine、Checkpoint 和 <a href="/s/webclips/wiki/concepts/agent-computer-interface.html">agent-computer-interface</a> ACI 规范进行设计。构建任何自动化流程，都需要确保配套部署了对等的无缝验证机制（Testing Harness）。</p><h2 id="源文章引用" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Effective harnesses for long-running agents.html">[Agent_Architecture] Effective harnesses for long-running agents</a></td><td>&quot;系统自动归档提炼的要点摘要...&quot;</td></tr><tr><td><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Building Effective AI Agents.html">[Agent_Architecture] Building Effective AI Agents</a></td><td>&quot;Maintain simplicity... Prioritize transparency... Carefully craft your ACI.&quot;</td></tr><tr><td><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Why Your “AI-First” Strategy Is Probably Wrong.html">[Agent_Architecture] Why Your “AI-First” Strategy Is Probably Wrong.md</a></td><td>&quot;I had to unify all the code into a single monorepo. One reason: so AI could see everything... The more of your system you pull into a form the agent can inspect, validate, and modify, the more leverage you get.&quot;</td></tr></tbody></table><h2 id="源文章引用-1" tabindex="-1">源文章引用 <a class="header-anchor" href="#源文章引用-1" aria-label="Permalink to &quot;源文章引用&quot;">​</a></h2><table tabindex="0"><thead><tr><th>来源</th><th>关键段落摘录</th></tr></thead><tbody><tr><td><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Effective harnesses for long-running agents.html">[Agent_Architecture] Effective harnesses for long-running agents</a></td><td>&quot;系统自动归档提炼的要点摘要...&quot;</td></tr><tr><td><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Harness-design-for-long-running-application-development.html">[Agent_Architecture] Harness-design-for-long-running-application-development</a></td><td>&quot;系统自动归档提炼的要点摘要...&quot;</td></tr></tbody></table>',13)])])}const A=e(i,[["render",o]]);export{u as __pageData,A as default};
